prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?org ?created WHERE {
  ?model a bboExt:Model .
  ?model tai:normalizedId "262d9e9b8c224d918fe800cd2a454ddf" .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . }
  OPTIONAL { ?model tai:modelCreated ?created . }
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?orgId ?originalId ?normalizedId WHERE {
  ?model a bboExt:Model .
  OPTIONAL { ?model bbo:name ?modelName . }
  OPTIONAL { ?model tai:belongsTo ?org . ?org tai:organizationId ?orgId . }
  OPTIONAL { ?model tai:originalId ?originalId . }
  OPTIONAL { ?model tai:normalizedId ?normalizedId . }
  FILTER(CONTAINS(LCASE(STR(?originalId)), "262d9e9b8c224d918fe800cd2a454ddf") || 
         CONTAINS(LCASE(STR(?normalizedId)), "262d9e9b8c224d918fe800cd2a454ddf") ||
         CONTAINS(LCASE(STR(?model)), "262d9e9b8c224d918fe800cd2a454ddf"))
}
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?taskName ?initPartRef ?loopType WHERE {
  ?task a bboExt:ChoreographyTask .
  ?task tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_ece51571_13ba_41d8_8688_057c876cc093> .
  OPTIONAL { ?task bbo:name ?taskName . }
  OPTIONAL { ?task bboExt:initiatingParticipantRef ?initPartRef . }
  OPTIONAL { ?task bboExt:loopType ?loopType . }
}
ORDER BY ?taskName
LIMIT 25

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?gatewayName ?direction ?default WHERE {
  ?gateway a bboExt:ExclusiveGateway .
  ?gateway tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_ece51571_13ba_41d8_8688_057c876cc093> .
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?direction . }
  OPTIONAL { ?gateway bboExt:default ?default . }
}
UNION
SELECT ?gateway ?gatewayName ?direction WHERE {
  ?gateway a bboExt:ParallelGateway .
  ?gateway tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_ece51571_13ba_41d8_8688_057c876cc093> .
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?direction . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?type ?gatewayName ?direction ?default WHERE {
  { ?gateway a bboExt:ExclusiveGateway . BIND("ExclusiveGateway" as ?type) }
  UNION
  { ?gateway a bboExt:ParallelGateway . BIND("ParallelGateway" as ?type) }
  ?gateway tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_ece51571_13ba_41d8_8688_057c876cc093> .
  OPTIONAL { ?gateway bbo:name ?gatewayName . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?direction . }
  OPTIONAL { ?gateway bboExt:default ?default . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?event ?type ?eventName ?isInterrupting WHERE {
  { ?event a bboExt:StartEvent . BIND("StartEvent" as ?type) }
  UNION
  { ?event a bboExt:EndEvent . BIND("EndEvent" as ?type) }
  ?event tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_ece51571_13ba_41d8_8688_057c876cc093> .
  OPTIONAL { ?event bbo:name ?eventName . }
  OPTIONAL { ?event bboExt:isInterrupting ?isInterrupting . }
}

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?mf ?sourceRef ?targetRef ?messageRef WHERE {
