  ?mf tai:belongsTo <https://www.teamingai-project.eu/kg/process/qualityInspection/sid_ece51571_13ba_41d8_8688_057c876cc093> .
  OPTIONAL { ?mf bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?mf bboExt:targetRef ?targetRef . }
  OPTIONAL { ?mf bboExt:messageRef ?messageRef . }
}
LIMIT 20
